import android.content.Context
import android.content.SharedPreferences
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey

class AuthenticationManager private constructor(context: Context) {

    companion object {
        private const val PREFS_FILE_NAME = "auth_encrypted_prefs"
        private const val KEY_AUTH_TOKEN = "key_auth_token"
        private const val KEY_USER_ID = "key_user_id"
        private const val KEY_IS_LOGGED_IN = "key_is_logged_in"
        private const val KEY_TOKEN_EXPIRY = "key_token_expiry"

        @Volatile
        private var instance: AuthenticationManager? = null

        fun getInstance(context: Context): AuthenticationManager {
            return instance ?: synchronized(this) {
                instance ?: AuthenticationManager(context.applicationContext).also {
                    instance = it
                }
            }
        }
    }

    private val sharedPreferences: SharedPreferences

    init {
        val masterKey = MasterKey.Builder(context.applicationContext)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()

        sharedPreferences = EncryptedSharedPreferences.create(
            context.applicationContext,
            PREFS_FILE_NAME,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    data class AuthState(
        val isLoggedIn: Boolean,
        val authToken: String?,
        val userId: String?,
        val tokenExpiry: Long
    )

    sealed class AuthResult {
        data class Success(val authState: AuthState) : AuthResult()
        data class Error(val message: String) : AuthResult()
    }

    fun saveAuthCredentials(authToken: String, userId: String, tokenExpiryMillis: Long): AuthResult {
        if (authToken.isBlank()) {
            return AuthResult.Error("Auth token cannot be blank")
        }
        if (userId.isBlank()) {
            return AuthResult.Error("User ID cannot be blank")
        }
        if (tokenExpiryMillis <= System.currentTimeMillis()) {
            return AuthResult.Error("Token expiry must be in the future")
        }

        return try {
            sharedPreferences.edit().apply {
                putString(KEY_AUTH_TOKEN, authToken)
                putString(KEY_USER_ID, userId)
                putBoolean(KEY_IS_LOGGED_IN, true)
                putLong(KEY_TOKEN_EXPIRY, tokenExpiryMillis)
                apply()
            }
            AuthResult.Success(
                AuthState(
                    isLoggedIn = true,
                    authToken = authToken,
                    userId = userId,
                    tokenExpiry = tokenExpiryMillis
                )
            )
        } catch (e: Exception) {
            AuthResult.Error("Failed to save credentials: ${e.message}")
        }
    }

    fun getAuthState(): AuthState {
        val isLoggedIn = sharedPreferences.getBoolean(KEY_IS_LOGGED_IN, false)
        val authToken = sharedPreferences.getString(KEY_AUTH_TOKEN, null)
        val userId = sharedPreferences.getString(KEY_USER_ID, null)
        val tokenExpiry = sharedPreferences.getLong(KEY_TOKEN_EXPIRY, 0L)

        if (isLoggedIn && tokenExpiry <= System.currentTimeMillis()) {
            clearAuthCredentials()
            return AuthState(
                isLoggedIn = false,
                authToken = null,
                userId = null,
                tokenExpiry = 0L
            )
        }

        return AuthState(
            isLoggedIn = isLoggedIn,
            authToken = authToken,
            userId = userId,
            tokenExpiry = tokenExpiry
        )
    }

    fun isLoggedIn(): Boolean {
        val state = getAuthState()
        return state.isLoggedIn && !state.authToken.isNullOrBlank()
    }

    fun getAuthToken(): String? {
        val state = getAuthState()
        return if (state.isLoggedIn) state.authToken else null
    }

    fun getUserId(): String? {
        val state = getAuthState()
        return if (state.isLoggedIn) state.userId else null
    }

    fun isTokenExpired(): Boolean {
        val tokenExpiry = sharedPreferences.getLong(KEY_TOKEN_EXPIRY, 0L)
        return tokenExpiry <= System.currentTimeMillis()
    }

    fun clearAuthCredentials() {
        sharedPreferences.edit().apply {
            remove(KEY_AUTH_TOKEN)
            remove(KEY_USER_ID)
            putBoolean(KEY_IS_LOGGED_IN, false)
            remove(KEY_TOKEN_EXPIRY)
            apply()
        }
    }

    fun logout(): AuthResult {
        return try {
            clearAuthCredentials()
            AuthResult.Success(
                AuthState(
                    isLoggedIn = false,
                    authToken = null,
                    userId = null,
                    tokenExpiry = 0L
                )
            )
        } catch (e: Exception) {
            AuthResult.Error("Failed to logout: ${e.message}")
        }
    }

    fun updateAuthToken(newToken: String, newExpiryMillis: Long): AuthResult {
        if (newToken.isBlank()) {
            return AuthResult.Error("New auth token cannot be blank")
        }
        if (newExpiryMillis <= System.currentTimeMillis()) {
            return AuthResult.Error("Token expiry must be in the future")
        }

        val userId = sharedPreferences.getString(KEY_USER_ID, null)
            ?: return AuthResult.Error("No existing user session found")

        return try {
            sharedPreferences.edit().apply {
                putString(KEY_AUTH_TOKEN, newToken)
                putLong(KEY_TOKEN_EXPIRY, newExpiryMillis)
                apply()
            }
            AuthResult.Success(
                AuthState(
                    isLoggedIn = true,
                    authToken = newToken,
                    userId = userId,
                    tokenExpiry = newExpiryMillis
                )
            )
        } catch (e: Exception) {
            AuthResult.Error("Failed to update token: ${e.message}")
        }
    }
}